def resumir_temperaturas(valores: list[object]) -> dict[str, object]:
    validos: list[float] = []
    rechazados = 0
    for valor in valores:
        if not isinstance(valor, (int, float)):
            rechazados += 1
            continue
        numero = float(valor)
        if not 30.0 <= numero <= 45.0:
            rechazados += 1
            continue
        validos.append(numero)
    promedio = sum(validos) / len(validos) if validos else None
    return {'promedio_c': promedio, 'validos': len(validos), 'rechazados': rechazados}

print(resumir_temperaturas([36.5, 'error', 37.2, 80, 35.9]))

TRANSICIONES = {
    ('recibido', 'validar_ok'): 'validado',
    ('recibido', 'validar_error'): 'rechazado',
    ('validado', 'procesar'): 'procesado',
}

def transicionar(estado: str, evento: str) -> str:
    try:
        return TRANSICIONES[(estado, evento)]
    except KeyError as error:
        raise ValueError(f'transición no permitida: {estado} + {evento}') from error

historial = ['recibido']
historial.append(transicionar(historial[-1], 'validar_ok'))
historial.append(transicionar(historial[-1], 'procesar'))

